## ICPC Medal
**思路：**
不看银牌都处理成铜牌。
**代码：**
```cpp
void solve()
{
    int a,b,c,x,y;
    cin>>a>>b>>c>>x>>y;
    c+=b*x;
    while(c>=x*y){
        int m=c/(x*y);
        a+=m;
        c=c-m*x*y+m;
    }
    cout<<a;
}
```

## Unique Number
**思路：**
最优的情况就是 $k,k-1,k-2...,k-i+1$
但是由于有 d 的限制，所以要保证 $k-i+1\le d$ 所以 $k\le d+i-1$。找到最小的 k 和 n 做对比得出答案。
**代码：**
```cpp
const int N=2e5+5;
int a;
void solve()
{
    int n;
    cin>>n;
    int ans=1e9;
    for(int i=1;i<=n;i++)
    {
        cin>>a;
        ans=min(ans,a+i-1);
    }
    cout<<min(ans+1,n)<<endl;
}
```
## Balanced Array
**思路：**
滑动窗口。两个滑动窗口存储当前窗口的最大值和最小值，然后进行判断，进行左端点的更新。
**代码：**
```cpp
const int N=2e5+5;
int a[N];
int qma[N],qmi[N];
void solve()
{
    int n;
    cin>>n;
    int ans=0;
    for(int i=0;i<n;i++)
    {
        cin>>a[i];
    }
    int h1=0,t1=-1;
    int h2=0,t2=-1;
    int l=0;
    for(int r=0;r<n;r++)
    {
        while(h1<=t1&&a[qma[t1]]<a[r])t1--;
        qma[++t1]=r;
        while(h2<=t2&&a[qmi[t2]]>a[r])t2--;
        qmi[++t2]=r;
        while(h1<=t1&&h2<=t2&&(a[qma[h1]]-a[qmi[h2]]>1))//两个队列不为空，如果不满足条件，对应队头出队。
        {
            if(qma[h1]==l)h1++;
            if(qmi[h2]==l)h2++;
            l++;//左端点右移
        }
        ans+=r-l+1;
        /*
        计算以r为右端点方案的个数
        [l,r],[l+1,r],...,[r-1,r],[r,r]
        */
    }
    cout<<ans<<endl;
}
```

## Maximize The Sum
**思路：**
如果数组中全为 0，数组不会发生变化。
一次修改后的三个数字的异或和变为 $x\oplus y\oplus z\oplus z\oplus x=0$，从这里可以看出修改后三个值是不可能得到全 1 的，除非数组本来都是 1。这样最多就只有 n-1。
一个 1 可以变成两个 1，不断重复下去必然能得到 n-1 个 1。
**代码：**
```cpp
void solve()
{
    int n;
    cin>>n;
    string s;
    cin>>s;
    bool f0=1,f1=1;
    for(int i=0;i<n;i++)
    {
        if(s[i]=='1'){
            f0=0;
        }else{
            f1=0;
        }
    }
    if(f0)cout<<"0"<<endl;
    else if(f1)cout<<n<<endl;
    else cout<<n-1<<endl;
}
```



F 明天补

**题目链接：** 
https://www.luogu.com.cn/problem/U549625

**思路：** 
要求区间和，可以想到用前缀和数组，区间和即为 `pre[r]-pre[l-1]`，要求最大化区间和即最大化 `pre[r]-pre[l-1]`，对于固定的 `i`，$i<r\le n,l-1<i$，所以我们其实是在 $max(pre[r]-pre[k]) k=l-1(0\le k<i)(i<r\le n)$ 。
这里可以开三个循环去做一下，两个子循环分别是枚举左端点和右端点。会超时。
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
#define PII pair<int,int>
const int N=2e5+5;
int a[N];
int s[N];//前缀和数组
void solve()
{
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        s[i]=s[i-1]+a[i];
    }
    for(int i=1;i<=n;i++)
    {
        int ma=-1e18;
        for(int l=1;l<=i;l++)
        {
            for(int r=i;r<=n;r++)
            {
                int sum=s[r]-s[l-1];
                ma=max(ma,sum);
            }
        }
        cout<<ma<<" ";
    }
}
signed main(){
	IOS
	//int t;
	//cin>>t;
	int t=1;
	while(t--)
	{
		solve();
	}
}
```
所以我们需要在 i 的左边找到一个最小的 `pre[k]` 在 i 的右边找到一个最大的 `pre[r]`。这样可以优化掉循环。

**正解代码：** 
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
#define PII pair<int,int>
const int N=2e5+5;
int a[N];
int s[N];//前缀和数组
int c[N];//来存储后缀最大值
void solve()
{
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        s[i]=s[i-1]+a[i];
    }
    c[n+1]=-1e18;
    for(int i=n;i>0;i--)
    {
        c[i]=max(c[i+1],s[i]);
    }
    int mi=0;
    for(int i=1;i<=n;i++)
    {
        int cur=c[i]-mi;
        cout<<cur<<" ";
        mi=min(mi,s[i]);
    }
}
signed main(){
	IOS
	//int t;
	//cin>>t;
	int t=1;
	while(t--)
	{
		solve();
	}
}

```

## 整数小拼接
**题目链接：** 
[P8708 [蓝桥杯 2020 省 A1] 整数小拼接 - 洛谷](https://www.luogu.com.cn/problem/P8708#ide)
**思路：** 
如果通过暴力循环去一个一个找的话能过 30 分。
```cpp
const int N=1e5+5;
int a[N];
int n,k;
bool check(int aa,int bb){
    string s;
    s=to_string(aa)+to_string(bb);
    int p=stoll(s);//string 转 longlong
    return p<=k;
}
void solve()
{
    cin>>n>>k;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    int cnt=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(i==j)continue;
            if(check(a[i],a[j])){
                cnt++;
            }
        }
    }
    cout<<cnt;
}
```
为了更好的做题，我们先给数组排个序。这样就好找规律了。
要使拼出来的数字小于等于 k，所以我们可以分析一下满足条件的 j 的取值。
如果我们将 `a[j]` 拼到 `a[i]` 后面，可以知道随着 i 的增大满足条件的 j 的个数会变少。
然后有进行了一次优化能过一半分数。
```cpp
bool check(int aa,int bb){
    string s;
    s=to_string(aa)+to_string(bb);
    int p=stoll(s);
    return p<=k;
}
void solve()
{
    cin>>n>>k;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    sort(a+1,a+1+n);
    int cnt=0;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(i==j)continue;
            if(check(a[i],a[j]))cnt++;
            else break;
        }
    }
    cout<<cnt;
}
```
这样还是超时的话，只能再考虑双指针优化了。

**正解代码：** 
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
#define PII pair<int,int>
const int N=1e5+5;
int a[N];
int n,k;
bool check(int aa,int bb){
    string s;
    s=to_string(aa)+to_string(bb);
    int p=stoll(s);
    return p<=k;
}
void solve()
{
    cin>>n>>k;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    sort(a+1,a+1+n);
    int cnt=0;
    int r=n;
    for(int i=1;i<=n;i++)
    {
        while(r>0&&!check(a[i],a[r]))r--;
        cnt+=r;
        if(r>=i)cnt--;
    }
    cout<<cnt;
}
signed main(){
	IOS
	//int t;
	//cin>>t;
	int t=1;
	while(t--)
	{
		solve();
	}
}
```
## 宇宙总统

**题目链接：** 

[P1781 宇宙总统 - 洛谷](https://www.luogu.com.cn/problem/P1781#ide)

**思路：** 

总感觉做过，就是转成字符串比较。

**代码：** 
```cpp
bool check(string a,string b){
    if(a.size()>b.size())return true;
    else if(a.size()<b.size())return false;
    else{
        for(int i=0;i<a.size();i++)
        {
            if(a[i]>b[i])return true;
            else if(a[i]<b[i])return false;
        }
        return true;
    }
}
void solve()
{
    int n;
    cin>>n;
    string m="0";
    int cnt=0;
    for(int i=1;i<=n;i++)
    {
        string x;
        cin>>x;
        if(check(x,m))
        {
            cnt=i;
            m=x;
        }
    }
    cout<<cnt<<endl<<m;
}
```
## 全排列的价值
**题目链接：** 

[P12369 [蓝桥杯 2022 省 Python B] 全排列的价值 - 洛谷](https://www.luogu.com.cn/problem/P12369)

**思路：** 

题目所描述的价值其实就是顺序对的数量。
对于 n 个数，所产生的全排列数是 $n!$，在所有排列中顺序对出现的概率是 $\frac{1}{2}$ 。所以一个特定位置 $(i,j)$ 在 $\frac{n!}{2}$ 个排列中是顺序对。
在一个排列中一共有多少种位置选择？$C_{n}^{2}$ 种。
所以所有排列中的顺序对数量为：$C_{n}^{2}*\frac{n!}{2}=\frac{n(n-1)\times n!}{4}$。

**代码：** 
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
#define PII pair<int,int>
const int MOD=998244353;
const int N=1e6+5;
int infact[N],fact[N];
int qmi(int a,int b,int p){
    int res=1;
    while(b){
        if(b&1)res=res*a%p;
        b>>=1;
        a=a*a%p;
    }
    return res%p;
}
void pre(){
    fact[0]=1,infact[0]=1;
    for(int i=1;i<=N;i++){
        fact[i]=fact[i-1]*i%MOD;
    }
}
void solve()
{
    int n;
    cin>>n;
    int cnt=0;
    cout<<fact[n]*n%MOD*(n-1)%MOD*qmi(4,MOD-2,MOD)%MOD;
}
signed main(){
	IOS
	//int t;
	//cin>>t;
	int t=1;
    pre();
	while(t--)
	{
		solve();
	}
}
```

## 狡兔 k 窟
**题目链接：** 

[P12126 [蓝桥杯 2024 省 B 第二场] 狡兔 k 窟 - 洛谷](https://www.luogu.com.cn/problem/P12126#ide)

**代码：** 
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
#define PII pair<int,int>
const int N=2e5+5;
int c[N];
const int M=4e5+5;
int e[N],ne[M],h[M],idx,w[M];
int dist[N];
bool st[N];
void add(int a,int b,int c)
{
    e[idx]=b;
    w[idx]=c;
    ne[idx]=h[a];
    h[a]=idx++;
}
void bfs(int u,int v){
    memset(dist,0x3f,sizeof dist);
    memset(st,0,sizeof st);
    dist[u]=0;
    queue<int>q;
    q.push(u);
    while(q.size()){
        auto t=q.front();
        q.pop();
        for(int i=h[t];i!=-1;i=ne[i]){
            int j=e[i];
            if(dist[j]>dist[t]+w[i]){
                dist[j]=dist[t]+w[i];
                q.push(j);
            }
        }
    }
    cout<<dist[v]<<endl;
}
void solve()
{
    int n,m;
    cin>>n>>m;
    memset(h,-1,sizeof h);
    for(int i=1;i<=n;i++)
    {
        cin>>c[i];
    }
    for(int i=1;i<n;i++){
        int u,v;
        cin>>u>>v;
        u=c[u],v=c[v];
        add(u,v,1);
        add(v,u,1);
    }
    while(m--){
        int s,t;
        cin>>s>>t;
        bfs(c[s],c[t]);
    }
}
signed main(){
	IOS
	//int t;
	//cin>>t;
	int t=1;
	while(t--)
	{
		solve();
	}
}
```
## 管道
**题目链接：** 
[P12380 [蓝桥杯 2023 省 Python B] 管道 - 洛谷](https://www.luogu.com.cn/problem/P12380#ide)
**思路：** 
二分时间。
**代码：** 
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
#define PII pair<int,int>
const int N=1e5+5;
int L[N],S[N];
int n,len;
bool check(int mid){
    int p=0;
    for(int i=1;i<=n;i++)
    {
        if(mid>=S[i]){
            if(p>=len)return true;
            int l=L[i]-(mid-S[i]);
            int r=L[i]+(mid-S[i]);
            if(l-1<=p)p=max(p,r);
        }
    }
    if(p>=len)return true;
    return false;
}
void solve()
{
    cin>>n>>len;
    for(int i=1;i<=n;i++)
    {
        cin>>L[i]>>S[i];
    }
    int l=1,r=2e9;
    while(l<r){
        int mid=l+r>>1;
        if(check(mid))r=mid;
        else l=mid+1;
    }
    cout<<l;
}
signed main(){
	IOS
	//int t;
	//cin>>t;
	int t=1;
	while(t--)
	{
		solve();
	}
}
```

## R 格式
**题目链接：** 
https://www.luogu.com.cn/problem/P10425
**思路：** 
模拟。高精度
**代码：** 
先来一个 50 分的做法。
```cpp
int qmi(int a,int b)
{
    int res=1;
    while(b){
        if(b&1)res=a*res;
        b>>=1;
        a=a*a;
    }
    return res;
}
void solve()
{
    int n;
    double d;
    cin>>n>>d;
    d*=qmi(2,n);
    cout<<(int)(d+0.5);
}
```
看到 $2^{1000}$ 就知道得用高精度。记录一下小数点的位置。对 $2^n$ 乘积可以看作累加。因为乘整数所以小数点的位置不会变。
以下内容复习高精度加减乘除法，会的同学可以直接跳过。
### 高精度加法
高精度加法的步骤：
1. 高精度数字利用字符串读入；
2. 把字符串反转翻转存入两个整型数组 A，B；
3. 从低位到高位，累加，进位，存余；
4. 把数组 C 从高位到低位依次输出。
```cpp
const int N=100005;
int A[N],B[N],C[N];
int la,lb,lc;
void add(int A[],int B[],int C[]){
    for(int i=0;i<lc;i++)
    {
        C[i]+=A[i]+B[i];//累加
        C[i+1]+=C[i]/10;//进位
        C[i]%=10;//存余
    }
    if(C[lc])lc++;//处理最高位
}
void solve()
{
    string a,b;
    cin>>a>>b;
    la=a.size(),lb=b.size(),lc=max(la,lb);
    for(int i=la-1;i>=0;i--){
        A[la-1-i]=a[i]-'0';//将字符形数字转化为数值
    }
    for(int i=lb-1;i>=0;i--){
        B[lb-1-i]=b[i]-'0';//将字符形数字转化为数值
    }
    //翻转存入方便进位。
    add(A,B,C);
    for(int i=lc-1;i>=0;i--){
        cout<<C[i];
    }
}
