    {
        cin>>v>>w;
        for(int j=1;j<=m;j++)
        {
            f[i][j]=f[i-1][j];
            if(j>=v)f[i][j]=max(f[i][j],f[i][j-v]+w);
        }
    }
    cout<<"max="<<f[n][m];
}*/
