# 混合背包
**题目链接：**
[T302125 混合背包 - 洛谷](https://www.luogu.com.cn/problem/T302125#ide)
**代码：**
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
#define PII pair<int,int>
const int N=1010;
int v[N],s[N],w[N];
int f[N];
void solve()
{
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        cin>>v[i]>>w[i]>>s[i];
    }
    for(int i=1;i<=n;i++)
    {
        if(!s[i])//完全背包
        {
            for(int j=v[i];j<=m;j++){
                f[j]=max(f[j],f[j-v[i]]+w[i]);
            }
        }
        else{
            if(s[i]==1){//01背包
                for(int j=m;j>=v[i];j--)
                {
                    f[j]=max(f[j],f[j-v[i]]+w[i]);
                }
            }else{//多重背包
                for(int k=1;k<=s[i];k<<=1)
                {
                    for(int j=m;j>=v[i]*k;j--){
                        f[j]=max(f[j],f[j-k*v[i]]+k*w[i]);
                    }
                    s[i]-=k;
                }
                if(s[i]){
                    for(int j=m;j>=v[i]*s[i];j--){
                        f[j]=max(f[j],f[j-s[i]*v[i]]+w[i]*s[i]);
                    }
                }
            }
        }
    }
    cout<<f[m];
}
