# 有依赖的背包问题
**题目链接：**
[U436983 有依赖的背包问题 - 洛谷](https://www.luogu.com.cn/problem/U436983#ide)
**代码：**
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
#define PII pair<int,int>
int n,m,root;
const int N=110;
int h[N],e[N],ne[N],idx;
int v[N],w[N];
int f[N][N];
void add(int a,int b){
    e[idx]=b;
    ne[idx]=h[a];
    h[a]=idx++;
}
void dfs(int u){
    for(int i=h[u];i!=-1;i=ne[i]){
        int s=e[i];
        dfs(s);
        for(int j=m-v[u];j>=0;j--){
            for(int k=0;k<=j;k++)
            {
                f[u][j]=max(f[u][j],f[u][j-k]+f[s][k]);
            }
        }
    }
    for(int j=m;j>=v[u];j--)f[u][j]=f[u][j-v[u]]+w[u];
    for(int j=0;j<v[u];++j)f[u][j]=0;
}
void solve()
{
    memset(h,-1,sizeof h);
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        int p;
        cin>>v[i]>>w[i]>>p;
        if(p==-1)root=i;
        else add(p,i);
    }
    dfs(root);
    cout<<f[root][m];
}
