**思路：**
和推导卡特兰数类似。
**代码：** 
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl '\n'
const int N=2e6+5;
int fact[N],infact[N];
const int MOD=1e9+7;
int qmi(int a,int b,int p)
{
    int res=1;
    while(b){
        if(b&1)res=res*a%p;
        b>>=1;
        a=a*a%p;
    }
    return res;
}
void init()
{
    fact[0]=infact[0]=1;
    for(int i=1;i<=N;i++)
    {
        fact[i]=fact[i-1]*i%MOD;
        infact[i]=infact[i-1]*qmi(i,MOD-2,MOD)%MOD;
    }
}
int C(int a,int b){
    if(b>a||b<0)return 0;
    return fact[a]*infact[b]%MOD*infact[a-b]%MOD;
}
void solve()
{
    int n,m,k;
    cin>>n>>m>>k;
    if(n>m+k){
        cout<<"0"<<endl;
        return;
    }
    int ans=(C(n+m,m)-C(n+m,m+k+1)+MOD)%MOD;
    cout<<ans;
}
signed main(){
	IOS
	//int t;
	//cin>>t;
    init();
	int t=1;
	while(t--)
	{
		solve();
	}
}
```

