## D 智乃的果子
**思路：** 
和合并石子类似，用小根堆来存，从小往大合并。每次取最轻的处理，两两合并，如果只有一个，那就取下个组的一个合并。
**代码：** 
```cpp
void solve()
{
    int n;
    cin>>n;
    int ans=0;
    int cnt=0;
    priority_queue<PII,vector<PII>,greater<PII>> p;
    for(int i=0;i<n;i++)
    {
        int c,w;
        cin>>c>>w;
        p.push({w,c});
        cnt+=c;
    }
    while(cnt>1){
        auto [w,c]=p.top();
        p.pop();
        if(c>1){
            int k=c/2;
            int r=c%2;
            int ww=w*2;
            ans=(ans+(k%MOD)*(ww%MOD)%MOD)%MOD;
            p.push({ww,k});
            if(r)p.push({w,r});
            cnt-=k;
        }else{
            auto [ww,cc]=p.top();
            p.pop();
            int www=ww+w;
            ans=(ans+www%MOD)%MOD;
            if(cc>1)p.push({ww,cc-1});
            p.push({www,1});
            cnt-=1;
        }
    }
    cout<<ans%MOD<<endl;
}
```
