            ne[m]=1;
            m=x^b[i];
            ne[m]=1;
        }
        for(int j=0;j<2048;j++)
            dp[j]=ne[j];
    }
    for(int i=2047;i>=0;i--)
    {
        if(dp[i]){
            cout<<i;
            break;
