## B 小L的彩球
**思路：**
要有 t 根线其实就是把这 n 个球分成 t+1 块，有两种情况，奇数块归左边或者是奇数块归右边。所以可以计算出左右两盒的块数，奇数块数在计算时需要上取整。然后其实就是在左边 x 个球中划分出 l 个块，就是 $C^{x-1}_{l-1}$，右边是 $C^{y-1}_{r-1}$。反之同理。
组合数的计算可以等之后会发一篇简单数学。
**代码：**
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define endl "\n"
const int MOD=998244353;
const int N=1e6+5;
int fact[N],infact[N];
int qmi(int a,int b)
{
    int res=1;
    while(b)
    {
        if(b&1){
            res=a*res%MOD;
        }
        b>>=1;
        a=a*a%MOD;
    }
    return res;
}
void pre()
{
    fact[0]=infact[0]=1;
    for(int i=1;i<N;i++)
    {
        fact[i]=fact[i-1]*i%MOD;
//         infact[i]=infact[i-1]*qmi(i,MOD-2)%MOD;
    }
    infact[N-1]=qmi(fact[N-1],MOD-2);
    for(int i=N-2;i>=0;i--){
        infact[i]=infact[i+1]*(i+1)%MOD;
    }
}
int C(int n,int k)
{
    if(k<0||k>n)return 0;
    return fact[n]*infact[k]%MOD*infact[n-k]%MOD;
}
void solve()
{
    int n,x,t;
    cin>>n>>x>>t;
    if(t==0){
        if(x==0||(n-x)==0){
            cout<<"1"<<endl;
        }else cout<<"0"<<endl;
        return;
    }
    int k=t+1;
    int ans=0;
    int l=(k+1)/2,r=k/2;
    if(l<=x&&r<=n-x&&l>0&&r>0){
        ans=(ans+C(x-1,l-1)*C(n-x-1,r-1)%MOD)%MOD;
    }
    if(r<=x&&l<=n-x&&l>0&&r>0){
        ans=(ans+C(x-1,r-1)*C(n-x-1,l-1)%MOD)%MOD;
    }
    cout<<ans<<endl;
}
signed main(){
	IOS
	int T;
	cin>>T;
    pre();
	//int t=1;
	while(T--)
	{
		solve();
	}
}
```
## A 小L的三角尺
**思路：**
考察数学的，首先明确三角形的斜边长度是两直角边的平方和。
那么打磨后的斜边长为 $\sqrt{(x^2+(y-t)^2)}$，对这个函数对 t 求导得 $-\frac{y-t}{\sqrt{(x^2+(y-t)^2)}}$。
可以把这个看成一个单位贡献值，也就是打磨 1 单位长度后斜边减少多少。这个值随着 t 得增加而减少。
将这个单位贡献值从大到小进行排列，每次打磨一单位后重新计算。用优先队列来存储。
然后就是简单的计算了，最后一个循环把现在的斜边长计算出来。
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define x first
#define y second
#define endl "\n"
#define PII pair<double,int>
const int N=5e5+5;
int a[N],b[N];
double r[N];
double cal(int i)//用来计算单位贡献值
{
    if(r[i]<=0)return 0.0;
    else return r[i]/sqrt(1.0*a[i]*a[i]+r[i]*r[i]);
}
void solve()
{
    int n,w;
    cin>>n>>w;
    double sum=0;
    int total=0;
    int aa=0;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i]>>b[i];
        r[i]=b[i];
        aa+=a[i];
        total+=b[i];
        sum+=sqrt(1.0*a[i]*a[i]+1.0*b[i]*b[i]);
    }
    if(w>=total){//惊天刚试了一下这个特判可以不用
        cout<<fixed<<setprecision(9)<<aa;
        return;
    }
    priority_queue<PII> p;//大根堆所以不用greater<>
    for(int i=1;i<=n;i++)
    {
        p.push({cal(i*1LL),i});
    }
    while(w&&!p.empty())
    {
        auto [f,i]=p.top();//取出当前最高贡献的
        p.pop();
        if(f=0)break;
        if(r[i]<=0)continue;
        w--;//打磨一单位
        r[i]--;//打磨一单位
        p.push({cal(i*1LL),i});//重新计算贡献后入队
    }
    double ans=0;
    for(int i=1;i<=n;i++)
    {
        ans+=sqrt(1.0*a[i]*a[i]+r[i]*r[i]);
    }
    cout<<fixed<<setprecision(9)<<ans;
}
signed main(){
	IOS
    int t=1;
	while(t--)
	{
		solve();
	}
}
```

