using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
#define x first
#define y second
#define endl "\n"
void solve()
{
    int n;
    cin>>n;
    int a=0,b=0,k=n;
    for(int i=1;i<=31;i++)
    {
        k<<=1;
        if((k&n)==0)
        {
            a=k,b=k+n;
            break;
        }
    }
    cout<<a<<" "<<b<<endl;
}
