    a[0]=k;
    int ans=-2e7;
    for(int i=0;i<=n;i++)
    {
        int last=(i+n)%(n+1);
        int sum=a[i]+a[last];
        ans=max(sum,ans);
    }
    cout<<ans<<endl;
}
