最后写一个蛇形矩阵的题的代码。
```java
import java.util.Scanner;
public class Main{
    public static void main(String[] args)
    {
        int n,m;
        Scanner sc=new Scanner(System.in);
        n=sc.nextInt();m=sc.nextInt();
        int[][] a=new int[n][m];
        int[] dx={0,1,0,-1},dy={1,0,-1,0};//对应右下左上
        for(int i=1,x=0,y=0,d=0;i<=n*m;i++)
        {
            a[x][y]=i;
            int xx=x+dx[d],yy=y+dy[d];
            if(xx<0||yy<0||xx>=n||yy>=m||a[xx][yy]!=0)
            {
                d=(d+1)%4;
                xx=x+dx[d];yy=y+dy[d];
            }
            x=xx;y=yy;
        }
        for(int i=0;i<n;i++)
        {
            for(int j=0;j<m;j++) System.out.print(a[i][j]+" ");
            System.out.println("");
        }
    }
}
```

