**题目链接：** https://codeforces.com/problemset/problem/2113/C
**题意：** 
有 n 座从左到右排列的建筑，其初始高度已知。对于每个位置`` i（1 ≤ i ≤ n）``，问：最少给第 `i `座建筑增加多少层，才能使其高度 严格大于 它右侧所有建筑的高度（即成为“豪华型房屋”）？
所有询问相互独立，实际高度不改变。
**思路：** 
从后往前找，每次更新右侧楼房高度最大值，如果当前楼房比最大高度低，则在最大高度上加一层。
**代码：** 
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
const int N=1e5+5;
int a[N];
int ans[N];
void solve()
{
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    int h=0;
    for(int i=n;i>0;i--)
    {
        if(a[i]>h)ans[i]=0;
        else ans[i]=h+1-a[i];
        h=max(h,a[i]);
    }
    for(int i=1;i<=n;i++)cout<<ans[i]<<" ";
}
signed main()
{
    int t=1;
    while(t--)
    {
        solve();
    }
}
```

**题目链接：** https://codeforces.com/problemset/problem/907/C
**题意：** 
给定 `n` 种字符串，三种不同的形式，`!` 表示受罚，`. `表示不受罚，`?` 表示猜测。保证最后一次才猜对。问能少被惩罚多少次。
**思路：** 
纯模拟，对于`! `串取交集，对`. ?`串取差集。建立一个待定字符集。每次按照题目要求进行待定集的修改，当待定字母数成为 `1` 之后的操作都是多余的。
**代码：** 
```cpp
#include<bits/stdc++.h>
using namespace std;
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
const int N=50;
int a[N];
void solve()
{
    int n;
    cin>>n;
    for(int i=0;i<26;i++)a[i]=1;//这里将待定集合都置为1.
    int num=26;//最初需要猜测26次
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        char op;
        cin>>op;
        string str;
        cin>>str;
        if(op=='.'){
            for(int j=0;j<str.size();j++)
            {
                if(a[str[j]-'a'])
                {
                    a[str[j]-'a']=0;//排除这个字母。
                    num--;
                }
            }
        }
        else if(op=='!')
        {
            //这时需要将待定集中非字符串内容去除
            if(num==1)ans++;//这时候要是能猜对了你还猜也挨电。
            int temp[26]={0};
            for(int j=0;j<str.size();j++)
            {
                temp[str[j]-'a']=1;
            }
            for(int j=0;j<26;j++)
            {
                if(a[j]&&temp[j]==0)
                {
                    a[j]=0;
                    num--;
                }
            }
        }else {
            if(i!=n){
                if(num==1)ans++;//表示此时只需要一次就能猜对了，但是多猜了一次
                if(a[str[0]-'a'])num--;
                a[str[0]-'a']=0;
            }
        }
    }
    cout<<ans;
}
signed main(){
    IOS
    int t=1;
    //cin>>t;
    while(t--)
    {
        solve();
    }
}
```

