void add(int a,int b)//a所对应的单链表中插入b a作为根
{ 
	e[idx]=b;
	ne[idx]=h[a];
	h[a]=idx++; 
}
初始时会将h置为-1表示无邻接点
idx初始值为0
执行add函数时，add(1,2)
e[0]=2,ne[0]=-1,h[1]=0;
此时的链表结构 [1] -> [2] -> NULL
for(int i=h[x];i!=-1;i=ne[i])遍历方法
```
**vector** 存图
```cpp
vector<int> p[N];
p[b].push_back(a);
这个存图看起来更简单
for(int i=0;i<p[x].size();i++)遍历也是
```
**代码：**
```cpp
//邻接表存图
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
const int N=1e5+5;
int h[N],e[N],ne[N],idx,ans[N];
void add(int a,int b)//a所对应的单链表中插入b  a作为根 
{
    e[idx]=b;
    ne[idx]=h[a];
    h[a]=idx++;
}
//h[x]邻接表存储树，有n个节点，所以需要n个队列头节点
//e[x]存储元素
//ne[x]存储列表的next值
void dfs(int x,int d)
{
    if(ans[x]) return;
    ans[x]=d;
    for(int i=h[x];i!=-1;i=ne[i]){
        int y=e[i];
        dfs(y,d);//递归标记所有邻接点
    }
}
void solve()
{
    memset(h,-1,sizeof h);
    int n,m;
    cin>>n>>m;
    for(int i=0;i<m;i++)
    {
        int a,b;
        cin>>a>>b;
        add(b,a);
    }
    for(int i=n;i>0;i--)
    {
        if(!ans[i])dfs(i,i);
    }
    for(int i=1;i<=n;i++)cout<<ans[i]<<" ";
}
