## P4779 【模板】单源最短路径（标准版）
**题目链接：** https://www.luogu.com.cn/problem/P4779
**思路：**
 单源最短路，无负权值，是一道 dijkstra 的题。
 死去的数据结构知识在攻击我。🐒🐒
 首先初始化所有节点的距离为无穷大，起点距离为 0，使用优先队列维护，优先处理距离最小的节点，遍历其所有邻接边，更新节点距离。一直重复直到队列为空。
**代码：**
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
typedef pair<int,int> PII;
priority_queue<PII,vector<PII>,greater<PII>> que;
const int M=2e5+5;
const int N=1e5+5;
int dis[N];//用于存储每个点到起点的最短距离
bool st[N];//用于在更新最短距离时 判断当前的点的最短距离是否确定 是否需要更新
int e[M],ne[M],h[N],idx,w[M];
void add(int a,int b,int c)
{
    e[idx]=b;
    ne[idx]=h[a];
    w[idx]=c;
    h[a]=idx++;
}
void dijkstra(int s)
{
    memset(dis, 0x3f, sizeof dis);
    que.push({0,s});//源点到自己距离是0；
    dis[s]=0;
    while(!que.empty())
    {
        auto x=que.top();
        que.pop();
        int dist=x.first,v=x.second;
        if(!st[v])
        {
            for(int i=h[v];i!=-1;i=ne[i])
            {
                int j=e[i];
                if(dis[j]>dist+w[i])
                {
                    dis[j]=dist+w[i];
                    que.push({dis[j],j});
                }
            }
            st[v]=true;
        }
    }
}
void solve()
{
    int n,m,s;
    cin>>n>>m>>s;
    memset(h,-1,sizeof h);
    for(int i=1;i<=m;i++)
    {
        int u,v,w;
        cin>>u>>v>>w;
        add(u,v,w);
    }
    dijkstra(s);
    for(int i=1;i<=n;i++)cout<<dis[i]<<" ";
}
signed main(){
	IOS
	//int t;
	//cin>>t;
	int t=1;
	while(t--)
	{
		solve();
	}
}
```

