## P1462 通往奥格瑞玛的道路
**题目链接：** https://www.luogu.com.cn/problem/P1462
**题目大意：** 要找出满足能走通到终点的最少的钱，血量还要够，
**思路：**
 看到最值了，考虑下二分，对于费用进行二分，对于血量用最短路。
**代码：**
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
typedef pair<int,int> PII;
const int M=2e5+5;
const int N=1e4+5;
int f[N];
int dis[N];//用于存储每个点到起点的血量消耗
bool st[N];//用于在更新最短距离时 判断当前的点的最短距离是否确定 是否需要更新
int e[M],ne[M],h[N],idx,w[M];
int n,m,b;
void add(int a,int b,int c)
{
    e[idx]=b;
    ne[idx]=h[a];
    w[idx]=c;
    h[a]=idx++;
}
bool dijkstra(int maxcost)
{
    if(f[1]>maxcost||f[n]>maxcost)return false;
    memset(st,0,sizeof st);
    memset(dis,0x3f,sizeof dis);
    priority_queue<PII,vector<PII>,greater<PII>> que;
    //从第一个城市0血出发，每经过一条边就增加对应的血量，如果血量超过b说明不行
    que.push({0,1});//源点到自己距离是0；
    dis[1]=0;
    while(!que.empty())
    {
        auto x=que.top();
        que.pop();
        int dist=x.first,v=x.second;
        if(!st[v])
        {
            for(int i=h[v];i!=-1;i=ne[i])
            {
                int j=e[i];
                if(f[j]>maxcost) continue;//钱超了
                if(dist+w[i]>b) continue;//血量超了
                if(dis[j]>dist+w[i]){
                    dis[j]=dist+w[i];
                    que.push({dis[j],j});
                }
            }
            st[v]=true;
        }
    }
    if(dis[n]<=b)return true;
    else return false;
}
void solve()
{
    cin>>n>>m>>b;
    memset(h,-1,sizeof h);
    int l=0x3f3f3f3f,r=-1;
    for(int i=1;i<=n;i++)
    {
        cin>>f[i];
        l=min(l,f[i]);
        r=max(r,f[i]);
    }
    for(int i=1;i<=m;i++)
    {
        int u,v,c;
        cin>>u>>v>>c;
        add(u,v,c);
        add(v,u,c);
    }
    int ans=-1;
    while(l<=r)
    {
        int mid=(l+r)>>1;
        if(dijkstra(mid)){
            ans=mid;
            r=mid-1;
        }else l=mid+1;
    }
    if(ans!=-1)cout<<ans;
    else cout<<"AFK";
}
signed main(){
	IOS
	//int t;
	//cin>>t;
	int t=1;
	while(t--)
	{
		solve();
	}
}
```

做完这个题之后 [C - Reindeer and Sleigh 2](https://atcoder.jp/contests/abc437/tasks/abc437_c)，就想起来之前做的 [125. 耍杂技的牛](https://www.acwing.com/problem/content/description/127/)这个题了。
**知识点：** 贪心
**分析：**
这个题的数据也是重量和力量，风险值(一头牛支撑不住的可能性)取决于它头上所有牛的总重量减去它的身体强壮程度的值
$risk = \sum_1^kw[i] - s$
这里把该牛上方 k 头牛的体重 w 求和与自身的强壮值 s 相减。
要得到最大风险值的最小可能值， 这句话可能比较难懂，就是要让所有牛的风险值最小，然后在这些最小的风险值中找一个最大的，我的想法是让下面的牛越强壮越好，上面的牛越轻越好(反过来就是下面的牛越重越好)，这样的话就是使 $s+w$ 越大越好。这里上次那个题是很像的。
**证明：**
我们假设第 `i` 位上的牛的 $s[i]+w[i]>s[i+1]+w[i+1]$ ⬅第 i+1 位的牛。
这里假设第 `i` 头牛是在第 `i+1` 头牛的上面。
按我们的想法当上面的牛的 $s+w$ 大于下面的牛的 $s+w$ 时我们就要进行交换

|     |            第 i 位上的牛            |        第 i+1 位上的牛         |
| :-: | :----------------------------: | :-----------------------: |
| 交换前 |    $\sum_1^{i-1}w[k]-s[i]$     |   $\sum_1^iw[k]-s[i+1]$   |
| 交换后 | $\sum_1^{i-1}w[k]+w[i+1]-s[i]$ | $\sum_1^{i-1}w[k]-s[i+1]$ |

交换后第 `i+1` 位上的牛上升，所以加上 `w[i+1]`。
再来分析一下风险值，我们可以看出四个值都带有 $\sum_1^{i-1}w[k]$，将它减去。

|     |   第 i 位上的牛    |  第 i+1 位上的牛   |
| :-: | :-----------: | :-----------: |
| 交换前 |    $-s[i]$    | $w[i]-s[i+1]$ |
| 交换后 | $w[i+1]-s[i]$ |   $-s[i+1]$   |

很容易得到 $(w[i+1]-s[i])>-s[i]$ 和 $(w[i]-s[i+1])>-s[i+1]$
现在只需要比较 $w[i+1]-s[i]$ 和 $w[i]-s[i+1]$。
当 $w[i+1]-s[i]>=w[i]-s[i+1]$ 时，$w[i+1]+s[i+1]>=w[i]+s[i]$，交换前更优。
当 $w[i+1]-s[i]<w[i]-s[i+1]$ 时，$w[i+1]+s[i+1]<w[i]+s[i]$， 交换后更优
由此可以得出当上面的牛的 $s+w$ 大于下面的牛的 $s+w$ 时我们就要进行交换。
**代码实现：**
```cpp
#include <bits/stdc++.h>
using namespace std;
#define x first
#define y second
#define int long long
typedef pair<int,int>PII;
const int N=5e4+5;
PII cow[N];
void solve()
{
    int n;
    cin>>n;
    for(int i=0;i<n;i++)
    {
        int s,w;
        cin>>w>>s;
        cow[i].x=s+w;
        cow[i].y=w;
    }
    sort(cow,cow+n);
    int sum=0,res=-1e9;
    //用来存最小的最大危险值,要用到max，所以起初定义很小。
    for(int i=0;i<n;i++)
    {
        int s=cow[i].x-cow[i].y,w=cow[i].y;
        res=max(sum-s,res);
        sum+=w;//记录总重
    }
    cout<<res;
    return;
}
signed main()
{
    int t=1;
    while(t--)
    {
        solve();
    }
}
```

