**链接**：[Problem - 1352B - Codeforces](https://codeforces.com/problemset/problem/1352/B)
要把 n 拆分成 k 个奇偶性相同的数。想一下一个奇数能不能拆分成偶数个？答案是不能。这里指的是拆分成奇偶性相同的数。这可以作为一个判断条件。
那一个偶数能不能拆分成奇数个？需要特殊判断一下，要拆分成偶数，最小的偶数是 2，所以 n 必须大于等于 2\*k。
当 k>n 时也不可能实现，当 k =n 时可以实现 (输出 k 个 1)。
这样之后，对于一个奇数，拆分成奇数个，可以拆分成 k-1 个 1 和 n-k+1。（偶数个 1 加上一个奇数）。偶数+奇数=奇数
```cpp
#include <bits/stdc++.h>
using namespace std;
#define int long long
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
void solve()
{
    int n,k;
    cin>>n>>k;
    if(k>n){
        cout<<"NO"<<endl;
        return;
    }
    if(n%2&&k%2==0)
    {
        cout<<"NO"<<endl;
        return;
    }
    if(n==k)
    {
        cout<<"YES"<<endl;
        for(int i=1;i<=k;i++)cout<<"1 ";
        cout<<endl;
        return;
    }
    if(n%2)
    {
        cout<<"YES"<<endl;
        for(int i=1;i<=k-1;i++)cout<<"1 ";
        cout<<n-k+1<<endl;
    }else{
        if(k%2&&n<2*k)
        {
        cout<<"NO"<<endl;
        return;
        }
        cout<<"YES"<<endl;
        if(n<2*k)
        {
            for(int i=1;i<=k-1;i++)cout<<"1 ";
            cout<<n-k+1<<endl;
        }else{
            for(int i=1;i<=k-1;i++)cout<<"2 ";
            cout<<n-2*(k-1)<<endl;
        }
    }
}
