```
1. 这里我们需要先预处理出 a<sup>2<sup>0</sup></sup>, a<sup>2<sup>1</sup></sup>, a<sup>2<sup>1</sup></sup>,..., a<sup>2<sup>logk</sup></sup>.这 log k个数
2. 对于一个数字 a<sup>k</sup>, 可以用a<sup>2<sup>0</sup></sup>, a<sup>2<sup>1</sup></sup>, a<sup>2<sup>1</sup></sup>,..., a<sup>2<sup>logk</sup></sup>.这 log k个数来组合，也就是 k用二进制形式来表示。
这个是处理多组数据的代码
```cpp
#include<bits/stdc++.h>
using namespace std;
using ll=long long;
ll qmi(int a,int k,int p)
{
    ll res=1%p;
    while(k)//对k进行二进制化,从低位到高位
    {
        if(k&1) res=res*a%p;
        k>>=1;
        //更新a,a依次为a^{2^0},a^{2^1},a^{2^2},....,a^{2^logk}
        a=(ll)a*a%p;//这里逐步更新a，边计算边处理
    }
    return res; 
}
int main()
{
    int n;
    cin>>n;
    while(n--)
    {
        int a,p,k;
        cin>>a>>k>>p;
        cout<<qmi(a,k,p)<<endl;
    }
    return 0;
}
```
