虽然直接用公式做题比较爽但是也学习一下用代码写这个操作
```cpp
class Solution {
public:
    int hammingDistance(int x, int y) {
        int s=x^y,cnt=0;
        while(s){
            cnt+=s&1;
            s>>=1;
        }
        return cnt;
    }
};
