#### Leetcode 476. 数字的补数
我们从左边到右边找到该二进制的第一个 1，t - 1，则该位后面的数都是 1111 这样形式，数字取反后和 t 与操作表明取取反结果后面的二进制
```cpp
class Solution {
public:
    int findComplement(int num) {
        if(!num) return 1;
        int t=0;
        for(int i=30;i>=0;i--)
        {
            if(num>>i&1){
                t=1<<i;
                break;
            }
        }
        t--;
        return ~num&t;
    }
};
```
