也看到了用掩码做题的；那就来学习一下吧
```cpp
class Solution {
public:
    int bitwiseComplement(int n) {
        if (n==0) return 1; // 特殊情况处理
        int ans=1;          // 初始化掩码为 1
        while(ans<=n){    // 循环直到掩码大于 n
            ans<<=1;        // 将掩码左移一位
        }
        return ans-1-n;   // 计算补数
    }
};
```
#### Leetcode 868. 二进制间距
这个题要求相邻 1 的最远距离，我们可以每次取 n 最后一位判断是否为 1，如果上一位为 1 则更新距离
```cpp
class Solution {
public:
    int binaryGap(int n) {
        int l=-1,ans=0;
        for(int i=0;n;i++)
        {
            if(n&1)
            {
                if(l!=-1)
                {
                    ans=max(ans,i-l);
                }
                l=i;
            }
            n>>=1;
        }
        return ans;
    }
};
```
#### Leetcode 2917. 找出数组中的 K-or 值
这里我们枚举每个元素的 0~30 比特位，统计该位为 1 的个数再对 ans 进行操作
```cpp
class Solution {
public:
    int findKOr(vector<int>& nums, int k) {
        int ans=0;
        for(int i=0;i<31;i++)
        {
            int cnt1=0;
            for(int x:nums){
                cnt1+=x>>i&1;
            }
            if(cnt1>=k){
                ans|=1<<i;
            }
        }
    }
    return ans;
};
```
#### Leetcode 693. 交替位二进制数
我的想法就是逐步遍历每一个二进制位
```cpp
class Solution {
public:
    bool hasAlternatingBits(int n) {
        int l=0;
        while(n){
            if(n&1)
            {
                if(l==1){
                    return false;
                }
                l=1;
                n>>=1;
