#### Leetcode 2657. 找到两个数组的前缀公共数组
这里是要取两个集合的交集，我们可以用 set 来去重，把两个数组中的元素均存入 set 中，然后减去 set 的大小即为重复元素的数量。
```cpp
class Solution {
public:
    vector<int> findThePrefixCommonArray(vector<int>& A, vector<int>& B) {
        int n=A.size();
        vector<int> c;
        unordered_set<int> cnt;
        for(int i=0;i<n;i++)
        {
            cnt.insert(A[i]);
            cnt.insert(B[i]);
            c.push_back(2*(i+1)-cnt.size());
        }
        return c;
    }
};
```
看看灵神的优雅代码把
```cpp
class Solution {
public:
    vector<int> findThePrefixCommonArray(vector<int>& A, vector<int>& B) {
        uint64_t p=0,q=0;//初始化两个 64 位无符号整数 p 和 q，用于存储两个数组中元素的位掩码。
        for(int i=0;i<A.size();i++)
        {
            p|=1ULL<<A[i];
    //将a[i]的位置在p中标记为1。1ULL<<a[i]生成一个只有第a[i]位为1的二进制数，然后与p进行按位或操作，将该位置标记为1。
            q|=1ULL<<B[i];
            A[i]=popcount(p&q);
            //计算 p 和 q 的按位与结果中 1 的个数，即两个数组中相同元素的个数。
        }
        return A;
    }
};
```
#### Leetcode 231. 2 的幂
这个问的是 2 的幂次，而不是偶数，如果 n 小于等于 0 那结果一定为 false。否则如果 n 是 2 的幂其二进制表示应该从第一位开始数第一个 1 即为最高位，也就是只有一个 1 。这个呢就是进行一次 lowbit 运算。
```cpp
class Solution {
public:
    bool isPowerOfTwo(int n) {
        return n>0&&((n&-n)==n);
    }
};
```
这里的判断方法还可以是我们对 n 减 1 再和 n 进行与运算
```cpp
class Solution {
public:
    bool isPowerOfTwo(int n) {
        return n>0&&(n&(n-1))==0;
    }
};
```
#### Leetcode 342. 4 的幂
可以确定一个数如果是 4 的幂一定是 2 的幂，那么就可以开平方后再验证是否为 2 的幂
```cpp
class Solution {
public:
    bool isPowerOfFour(int n) {
        if(n<=0)return false;
        int t=sqrt(n);
        return t*t==n&&(t&(t-1))==0;
    }
};
```
