#### Leetcode 2154. 将找到的值乘以 2
这个题我们可以用哈希表记录数组元素，再用函数判断元素是否在数组中。
```cpp
class Solution {
public:
    int findFinalValue(vector<int>& nums, int original) {
        unordered_set<int> s(nums.begin(),nums.end());
        while(s.count(original))original*=2;
        return original;
    }
};
```
也可以排序一下直接找
```cpp
class Solution {
public:
    int findFinalValue(vector<int>& nums, int original) {
        sort(nums.begin(),nums.end());
        for(auto x:nums)
        {
            if(x==original) original*=2;
        }
        return original;
    }
};
```
